@page "/Account/Login"
@using Microsoft.AspNetCore.Identity
@using sv_bea9cc61398d4184acb4e0eeeb50aea1.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h2>Login</h2>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }
        <form method="post" @formname="login">
            <AntiforgeryToken />
            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <input type="email" class="form-control" id="email" name="Email"
                       value="@Input.Email" required />
            </div>
            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <input type="password" class="form-control" id="password" name="Password" required />
            </div>
            <button type="submit" class="btn btn-primary w-100">Log in</button>
        </form>
    </div>
</div>

@code {
    private string? errorMessage;

    [SupplyParameterFromForm]
    private LoginModel Input { get; set; } = new();

    [SupplyParameterFromQuery]
    private string? ReturnUrl { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (HttpMethods.IsPost(HttpContext.Request.Method))
        {
            var result = await SignInManager.PasswordSignInAsync(
                Input.Email, Input.Password, isPersistent: false, lockoutOnFailure: false);

            if (result.Succeeded)
            {
                Navigation.NavigateTo(ReturnUrl ?? "/", forceLoad: true);
                return;
            }

            errorMessage = "Invalid email or password.";
        }
    }

    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;

    private sealed class LoginModel
    {
        public string Email { get; set; } = string.Empty;
        public string Password { get; set; } = string.Empty;
    }
}

@page "/Account/Logout"
@using Microsoft.AspNetCore.Identity
@using sv_bea9cc61398d4184acb4e0eeeb50aea1.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

@code {
    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;

    protected override async Task OnInitializedAsync()
    {
        if (HttpMethods.IsPost(HttpContext.Request.Method))
        {
            await SignInManager.SignOutAsync();
            Navigation.NavigateTo("/", forceLoad: true);
        }
    }
}

<PageTitle>Logout</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4 text-center">
        <h2>Log out</h2>
        <form method="post" @formname="logout">
            <AntiforgeryToken />
            <button type="submit" class="btn btn-secondary">Click here to log out</button>
        </form>
    </div>
</div>

@page "/admin/users"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@using sv_bea9cc61398d4184acb4e0eeeb50aea1.Data
@attribute [Authorize(Roles = "Admin")]
@rendermode InteractiveServer
@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Manage all users and their assigned roles.</p>

@if (users is null)
{
    <p><em>Loading users...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Full Name</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in users)
            {
                <tr>
                    <td>@user.Email</td>
                    <td>@user.FullName</td>
                    <td>@string.Join(", ", roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(ApplicationUser User, IList<string> Roles)>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var result = new List<(ApplicationUser, IList<string>)>();

        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add((user, roles));
        }

        users = result;
    }
}

@page "/directory"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@using sv_bea9cc61398d4184acb4e0eeeb50aea1.Data
@attribute [Authorize]
@rendermode InteractiveServer
@inject UserManager<ApplicationUser> UserManager

<PageTitle>Employee Directory</PageTitle>

<h1>Employee Directory</h1>
<p>Accessible to all authenticated users.</p>

@if (employees is null)
{
    <p><em>Loading directory...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Email</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var employee in employees)
            {
                <tr>
                    <td>@employee.FullName</td>
                    <td>@employee.Email</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ApplicationUser>? employees;

    protected override async Task OnInitializedAsync()
    {
        await Task.CompletedTask;
        employees = UserManager.Users.OrderBy(u => u.FullName).ToList();
    }
}

